// Primary Function called when the JSON Schema corresponding to POST order is checked
// Calls other schema Check funtion
private static function jsonChecks($restId, $dataArray, $status)
{
    $status["POST_ORDER_PRODUCTSLIST"]       = array();
    $status["POST_ORDER_TAX"]                = array();
    $status["POST_ORDER_ADDITIONAL_CHARGES"] = array();
    $status["POST_ORDER_PAYMENTS"]           = array();
    $status["POST_ORDER_DISCOUNTS"]          = array();

    $status = JSON::schemaCheck($dataArray, $status, "POST_ORDER");
    if (isset($dataArray["isNoCharge"])) {
        $isNoCharge = $dataArray["isNoCharge"];
    } else {
        $isNoCharge = 0;
    }
    if ($isNoCharge != 1) {
        if (isset($dataArray["paymentList"])) {
            for ($i = 0; $i < count($dataArray["paymentList"]); $i++) {
                $status = JSON::schemaCheck($dataArray["paymentList"][$i], $status, "POST_ORDER_PAYMENTS");
            }
        } else {
            $status["status"]              = $status["status"] & false;
            $status["POST_ORDER_PAYMENTS"] = "Required, but absent";
        }
    }

    if (isset($dataArray["productsList"])) {
        for ($i = 0; $i < count($dataArray["productsList"]); $i++) {
            $status = JSON::schemaCheck($dataArray["productsList"][$i], $status, "POST_ORDER_PRODUCTSLIST");
        }
    } else {
        $status["jsonProductsListSchema"] = "POST_ORDER_PRODUCTSLIST";
        $status["status"]                 = $status["status"] & false;
    }

    if ($status["status"] == false) {
        return $status;
    }

    for ($i = 0; $i < count($dataArray["productsList"]); $i++) {
        if (isset($dataArray["productsList"][$i]["taxes"])) {
            for ($j = 0; $j < count($dataArray["productsList"][$i]["taxes"]); $j++) {
                $status = JSON::schemaCheck($dataArray["productsList"][$i]["taxes"][$j], $status, "POST_ORDER_TAX");
            }
        }
    }

    if (isset($dataArray["additionalCharges"])) {
        for ($i = 0; $i < count($dataArray["additionalCharges"]); $i++) {
            $status = JSON::schemaCheck($dataArray["additionalCharges"][$i], $status, "POST_ORDER_ADDITIONAL_CHARGES");
        }
    }

    for ($i = 0; $i < count($dataArray["productsList"]); $i++) {
        if (isset($dataArray["productsList"][$i]["additionalCharges"])) {
            for ($j = 0; $j < count($dataArray["productsList"][$i]["additionalCharges"]); $j++) {
                $status = JSON::schemaCheck($dataArray["productsList"][$i]["additionalCharges"][$j], $status, "POST_ORDER_ADDITIONAL_CHARGES");
            }
        }
    }

    for ($i = 0; $i < count($dataArray["productsList"]); $i++) {
        if (isset($dataArray["productsList"][$i]["discounts"])) {
            for ($j = 0; $j < count($dataArray["productsList"][$i]["discounts"]); $j++) {
                $status = JSON::schemaCheck($dataArray["productsList"][$i]["discounts"][$j], $status, "POST_ORDER_DISCOUNTS");
            }
        }
    }

    if ($status["status"] == 1) {

        unset($status["POST_ORDER_PRODUCTSLIST"]);
        unset($status["POST_ORDER_TAX"]);
        unset($status["POST_ORDER_ADDITIONAL_CHARGES"]);
        unset($status["POST_ORDER_PAYMENTS"]);
        unset($status["POST_ORDER_DISCOUNTS"]);

