public static function orderInsert($storeID, $orderArray)
{
    $accountingArray = array();
    $timezone  = $orderArray["timezone"];
    date_default_timezone_set('UTC');
    $accountLogTimeUTC = date("Y-m-d H:i:s");
    $timezone = $orderArray['timezone'];
    date_default_timezone_set($timezone);
    $accountLogTimeLocal = date('Y-m-d H:i:s');

    $accountCount = 0;
    $temp         = array();
    $where        = "Order Placed";
    $temp         = self::createPayments($storeID, $orderArray, $where);
    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }
    $accountingCount = count($accountingArray);
    $temp            = self::createItemSales($storeID, $orderArray);

    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }
    $accountingCount = count($accountingArray);
    $temp            = self::createTaxes($storeID, $orderArray);

    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }

    $accountingCount = count($accountingArray);
    $temp            = self::createDiscounts($storeID, $orderArray);

    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }

    $accountingCount = count($accountingArray);


    $temp = self::createAdditionalCharges($storeID, $orderArray);
    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }

    $accountingCount = count($accountingArray);
    $temp            = self::createRoundingOff($storeID, $orderArray);

    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }

    $accountingCount = count($accountingArray);
    $temp            = self::createOpenBillItemSales($storeID, $orderArray);

    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }

    $accountingCount = count($accountingArray);
    $temp            = self::createOpenBillTaxes($storeID, $orderArray);

    for ($i = 0; $i < count($temp); $i++) {
        $accountingArray[$accountCount] = $temp[$i];
        $accountCount++;
    }

    $accountCount = count($accountingArray);
    for ($i=0; $i < $accountCount; $i++) { 
        $accountingArray[$i]["accountLogTimeLocal"]   = $accountLogTimeLocal;
        $accountingArray[$i]["accountLogTimeUTC"]   = $accountLogTimeUTC;
        $accountingArray[$i]["transactionUser"]   = $orderArray['billingUsername'];
