    return $accountingArray;
}

// Reverse the rounding and pass it as arrays 
public static function reverseRounding($storeID, $reverseOrderArray)
{
    $accountingTable = Constants::getTableName($storeID, "orderAccounting");
    $roundArray      = array();

    $orderId         = $reverseOrderArray["orderID"];
    $timezone        = $reverseOrderArray["timezone"];
    $transactionTime = $reverseOrderArray["refundSettledTime"];
    //  $orderId        = $reverseOrderArray["orderID"];

    for ($i = 0; $i < count($reverseOrderArray["roundingUpdate"]); $i++) {
        $roundArray[$i]["orderID"]              = $orderId;
        $roundArray[$i]["timezone"]             = $timezone;
        $roundArray[$i]["transactionTimeLocal"] = $transactionTime;
        $roundArray[$i]["transactionTimeLocal"] = $transactionTime;


        $roundArray[$i]["posDate"] = $reverseOrderArray["posDate"];

        $roundArray[$i]["accountType"] = $reverseOrderArray["roundingUpdate"][$i]["accountType"];
        $roundArray[$i]["accountID"]   = $reverseOrderArray["roundingUpdate"][$i]["accountID"];
        $roundArray[$i]["accountName"] = $reverseOrderArray["roundingUpdate"][$i]["accountName"];
        if ($reverseOrderArray["roundingUpdate"][$i]["amount"] > 0) {
            $roundArray[$i]["debit"]  = 0.0000;
            $roundArray[$i]["credit"] = $reverseOrderArray["roundingUpdate"][$i]["amount"];
        } else {
            $roundArray[$i]["debit"]  = -$reverseOrderArray["roundingUpdate"][$i]["amount"];
            $roundArray[$i]["credit"] = 0.0000;
        }
        $roundArray[$i]["transactionTypeID"] = "TRN_ORDER_CANCEL";
        $roundArray[$i]["exchange"]          = $roundArray[$i]["debit"] - $roundArray[$i]["credit"];
        if (isset($reverseOrderArray["refundOrderID"])) {
            $roundArray[$i]["refundedOrderID"] = $reverseOrderArray["refundOrderID"];
        }
        if (isset($reverseOrderArray["deviceID"])) {
            $roundArray[$i]["accountDeviceID"] = $reverseOrderArray["deviceID"];
        }

    }
    return $roundArray;
}

