// Returns item sales information
public static function createItemSales($storeID, $orderArray)
{
    $orderId              = $orderArray["orderID"];
    $transactionTimeLocal = $orderArray["billSettledTimeLocal"];
    $timezone             = $orderArray["timezone"];

    $accountsInformation["accounts"] = self::accountDetails($storeID, "ACC_SALES");

    $accountingArray = array();

    $count = 0;

    for ($i = 0; $i < count($orderArray["productsList"]); $i++) {
        if (!isset($orderArray["productsList"][$i]))
            $i++;
        $accountingArray[$count]["orderID"]     = $orderId;
        $accountingArray[$count]["timezone"]    = $timezone;
        $accountingArray[$count]["orderSubID"]  = $orderArray["productsList"][$i]["orderSubID"];
        $accountingArray[$count]["accountType"] = "ACC_SALES";
        $accountingArray[$count]["posDate"]     = $orderArray["posDate"];

        $accountingArray[$count]["accountID"]   = $accountsInformation["accounts"]["accountID"];
        $accountingArray[$count]["accountName"] = $accountsInformation["accounts"]["accountName"];
        $additionalSum                          = 0;

        $accountingArray[$count]["debit"]    = 0.0000;
        $accountingArray[$count]["credit"]   = $orderArray["productsList"][$i]["itemSales"] /*- $additionalSum*/ ;
        $accountingArray[$count]["exchange"] = $accountingArray[$count]["debit"] - $accountingArray[$count]["credit"];

        $accountingArray[$count]["transactionQuantity"]  = $orderArray["productsList"][$i]["quantityOrdered"];
        // Hard Coded from globalTypeValues for TRN_ORDER
        $accountingArray[$count]["transactionTypeID"] = "TRN_ORDER";

        $accountingArray[$count]["transactionTimeLocal"] = $transactionTimeLocal;
        $accountingArray[$count]["transactionTimeUTC"]   = localtoUTC($accountingArray[$count]["transactionTimeLocal"], $accountingArray[$count]["timezone"]);
        $count++;
    }


    return $accountingArray;
}

// Returns discounts
public static function createDiscounts($storeID, $orderArray)
{
    $orderId              = $orderArray["orderID"];
    $transactionTimeLocal = $orderArray["billSettledTimeLocal"];
    $timezone             = $orderArray["timezone"];

    $accountingArray = array();

    $count = 0;

    // Subsection to count Taxes on all products
    $discountCountArray = array();
    $discountCount      = 0;


    // Calculate taxes count
    for ($i = 0; $i < count($orderArray["productsList"]); $i++) {
        if (!isset($orderArray["productsList"][$i]))
            $i++;
        if (isset($orderArray["productsList"][$i]["discounts"])) {
            $discountCountArray[$i] = count($orderArray["productsList"][$i]["discounts"]);
            $discountCount += $discountCountArray[$i];
        }
    }

    // For each product add tax information to the accounting array
    for ($i = 0; $i < count($orderArray["productsList"]); $i++) {
        if (!isset($orderArray["productsList"][$i]))
            $i++;
        if (isset($orderArray["productsList"][$i]["discounts"]) && !empty($orderArray["productsList"][$i]["discounts"])) {
             $tCount = 0;
            if ($orderArray["productsList"][$i]["discounts"][$tCount]['discountID'] != -1) {

                while ($count < $discountCount && $tCount < $discountCountArray[$i]) {
                    $accountingArray[$count]["orderID"]     = $orderId;
                    $accountingArray[$count]["timezone"]    = $timezone;
                    $accountingArray[$count]["orderSubID"]  = $orderArray["productsList"][$i]["orderSubID"];
                    $accountingArray[$count]["transactionQuantity"]  = $orderArray["productsList"][$i]["quantityOrdered"];

                    $accountingArray[$count]["accountType"] = "ACC_DISCOUNT";
                    $accountingArray[$count]["posDate"]     = $orderArray["posDate"];

                    $discountID                                           = $orderArray["productsList"][$i]["discounts"][$tCount]["discountID"];
                    //  $accountingArray[$count]["transactionTypeID"]    = 0;
                    $accountingArray[$count]["accountID"]            = $orderArray["productsList"][$i]["discounts"][$tCount]["accountID"];

                    $accountingArray[$count]["accountName"]          = $orderArray["productsList"][$i]["discounts"][$tCount]["accountName"];
                    $accountingArray[$count]["credit"]                = 0.0000;
                    $accountingArray[$count]["debit"]               = $orderArray["productsList"][$i]["discounts"][$tCount]["discountPrice"];
                    $accountingArray[$count]["exchange"]             = $accountingArray[$count]["debit"] - $accountingArray[$count]["credit"];
                    // Hard Coded from globalTypeValues for TRN_ORDER
                    $accountingArray[$count]["transactionTypeID"]    = "TRN_ORDER";

                    $accountingArray[$count]["transactionTimeLocal"] = $transactionTimeLocal;
                    $accountingArray[$count]["transactionTimeUTC"]   = localtoUTC($transactionTimeLocal, $timezone);
                    $tCount++;
                    $count++;
                }                   
            }


        }
    }


    return $accountingArray;
}

